}

// Client Component: 处理实时交互
'use client';
function ChatClient({ initialTools, initialServers }) {
  const [messages, setMessages] = useState([]);
  const [servers, setServers] = useState(initialServers);

  useEffect(() => {
    // 建立WebSocket连接获取实时更新
    const ws = new WebSocket('/api/stream');
    ws.onmessage = (e) => {
      const event = JSON.parse(e.data);
      if (event.type === 'server_status') {
        setServers(event.payload);
      }
    };
    return () => ws.close();
  }, []);

  // ...
}
```
4. **优势**：减少客户端初始JS体积（Tool Schema不需要在bundle中）；服务端直接访问内部MCP Registry，无需额外API调用；提升首屏加载速度（初始数据已在HTML中）。

1. **XSS防御**：所有用户输入和LLM输出必须经过DOMPurify净化后再渲染；使用react-markdown等库而非dangerouslySetInnerHTML；代码高亮使用Prism/shiki的纯文本方式，不直接操作DOM；CSP策略限制inline script和eval：`Content-Security-Policy: default-src 'self'; script-src 'self';`；对URL进行校验，禁止javascript: protocol。
2. **Prompt Injection防御**：前端不直接参与Prompt安全（这是后端职责），但前端需要传递可信的上下文标识；在消息渲染中，区分"用户消息"和"系统消息"的视觉样式，防止LLM输出伪装成系统指令；对Tool执行结果进行预览限制（如只显示前1000字符），防止LLM输出超长的Injection Payload。
3. **Markdown安全渲染**：
```typescript
import DOMPurify from 'dompurify';
import ReactMarkdown from 'react-markdown';

const SafeMarkdown = ({ content }: { content: string }) => {
  // 先净化原始内容
  const sanitized = DOMPurify.sanitize(content, {
    ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'code', 'pre', 'ul', 'ol', 'li', 'a', 'blockquote'],
    ALLOWED_ATTR: ['href', 'title', 'class'],
  });

  // 对a标签添加安全校验
  const linkRenderer = ({ href, children }: any) => {
    if (!href || href.startsWith('javascript:')) {
      return <span>{children}</span>;
    }
    return <a href={href} target="_blank" rel="noopener noreferrer">{children}</a>;
  };

  return (
    <ReactMarkdown
      components={{ a: linkRenderer }}
    >
      {sanitized}
    </ReactMarkdown>
  );
};
```
4. **纵深防御**：前端净化是第一层，后端在将内容存入LLM Prompt前应再次净化；输出侧对LLM生成的HTML/JS进行过滤；审计日志记录所有可疑输入模式。

