2. **执行引擎**：
```typescript
class ToolExecutionEngine {
  async executeBatch(calls: ToolCall[], context: ExecutionContext): Promise<ToolResult[]> {
    // 1. 校验参数
    for (const call of calls) {
      const tool = this.registry.get(call.toolName);
      validate(call.arguments, tool.parameters);
    }

    // 2. 检查权限和确认
    for (const call of calls) {
      const tool = this.registry.get(call.toolName);
      if (tool.requiresConfirmation && !context.isConfirmed(call)) {
        await this.requestUserConfirmation(call);
      }
    }

    // 3. 分组并行执行（无依赖的并行，有依赖的串行）
    const groups = this.buildDependencyGraph(calls).topologicalGroups();
    const results: ToolResult[] = [];
    for (const group of groups) {
      const groupResults = await Promise.all(
        group.map(call => this.executeWithTimeout(call, tool.maxExecutionTime))
      );
      results.push(...groupResults);
    }
    return results;
  }
}
```
3. **错误处理**：可恢复错误（如文件不存在）返回给LLM，由LLM决定重试或修正；不可恢复错误（如权限拒绝）向用户报告并停止；超时错误支持部分结果返回（如"已处理50个文件中的30个"）。

